# Purpose: Load TPC-H data at scale factor 10 (SF10 ≈ 10 GB) into the tpch database
#          using the cpimport bulk loader for MariaDB ColumnStore.
#          Files are pipe-delimited .tbl files generated by dbgen.

cpimport tpch nation    /data/tpch/SF10/nation.tbl
cpimport tpch region    /data/tpch/SF10/region.tbl
cpimport tpch part      /data/tpch/SF10/part.tbl
cpimport tpch supplier  /data/tpch/SF10/supplier.tbl
cpimport tpch partsupp  /data/tpch/SF10/partsupp.tbl
cpimport tpch customer  /data/tpch/SF10/customer.tbl
cpimport tpch orders    /data/tpch/SF10/orders.tbl
cpimport tpch lineitem  /data/tpch/SF10/lineitem.tbl
